-- Aula 1: O que é Programação?
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Seu Primeiro Programa',
  'description', 'Crie um programa que exibe uma mensagem de boas-vindas personalizada.',
  'initialCode', '// Escreva um código que exibe "Bem-vindo ao mundo da programação, [seu nome]!"\n// Dica: Use console.log()\n\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'console.log("Bem-vindo ao mundo da programação, João!");', 'expected', 'Bem-vindo ao mundo da programação, João!')
  )
) WHERE id = 1;

-- Aula 2: Variáveis e Tipos de Dados
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Calculadora de Idade',
  'description', 'Crie variáveis para armazenar seu nome e ano de nascimento, depois calcule sua idade.',
  'initialCode', '// Crie as variáveis nome e anoNascimento\n// Calcule a idade (2026 - anoNascimento)\n// Exiba: "[nome] tem [idade] anos"\n\nconst nome = "Seu Nome";\nconst anoNascimento = 2000;\n// Complete o código aqui\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'const nome = "Maria"; const anoNascimento = 1995; const idade = 2026 - anoNascimento; console.log(nome + " tem " + idade + " anos");', 'expected', 'Maria tem 31 anos')
  )
) WHERE id = 2;

-- Aula 3: Funções
UPDATE lessons SET exercise_data = JSON_OBJECT(
  'title', 'Função de Saudação',
  'description', 'Crie uma função que recebe um nome e retorna uma saudação personalizada.',
  'initialCode', '// Crie uma função chamada saudar que recebe um parâmetro nome\n// A função deve retornar "Olá, [nome]! Seja bem-vindo!"\n\nfunction saudar(nome) {\n  // Seu código aqui\n}\n\nconsole.log(saudar("Ana"));\n',
  'testCases', JSON_ARRAY(
    JSON_OBJECT('input', 'function saudar(nome) { return "Olá, " + nome + "! Seja bem-vindo!"; } console.log(saudar("Ana"));', 'expected', 'Olá, Ana! Seja bem-vindo!')
  )
) WHERE id = 3;

